class RangeModule:

    def __init__(self):
        self.intervals = []

    def addRange(self, left: int, right: int) -> None:
        if self.intervals and self.intervals[-1][1] >= left:
            self.intervals[-1] = (self.intervals[-1][0], right)
        else:
            self.intervals.append((left, right))

    def queryRange(self, left: int, right: int) -> bool:
        for start, end in self.intervals:
            if start <= right and left <= end:
                return True
        return False

    def removeRange(self, left: int, right: int) -> None:
        self.intervals = [(start, end) for start, end in self.intervals if start >= right or end <= left]
        self.intervals.sort()
```
